use lean_core::Symbol;
use rust_decimal::Decimal;
use std::collections::HashMap;

/// Simplified portfolio target for execution (avoids depending on lean-portfolio-construction)
#[derive(Debug, Clone)]
pub struct ExecutionTarget {
    pub symbol: Symbol,
    /// Desired quantity (positive = long, negative = short, 0 = liquidate)
    pub quantity: Decimal,
}

/// An order request generated by execution
#[derive(Debug, Clone)]
pub struct OrderRequest {
    pub symbol: Symbol,
    pub quantity: Decimal,
    pub order_type: ExecutionOrderType,
    pub limit_price: Option<Decimal>,
    pub tag: String,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ExecutionOrderType {
    Market,
    Limit,
    MarketOnOpen,
    MarketOnClose,
}

/// Current security data needed by execution models
#[derive(Debug, Clone)]
pub struct SecurityData {
    pub symbol: Symbol,
    pub price: Decimal,
    pub bid: Option<Decimal>,
    pub ask: Option<Decimal>,
    pub volume: Option<Decimal>,
    pub average_volume: Option<Decimal>,
    pub daily_std_dev: Option<Decimal>,
    pub current_quantity: Decimal, // currently held
}

/// Converts portfolio targets into orders. Mirrors C# IExecutionModel.
pub trait IExecutionModel: Send + Sync {
    fn execute(
        &mut self,
        targets: &[ExecutionTarget],
        securities: &HashMap<String, SecurityData>,
    ) -> Vec<OrderRequest>;

    fn on_securities_changed(&mut self, _added: &[Symbol], _removed: &[Symbol]) {}
    fn name(&self) -> &str {
        "ExecutionModel"
    }
}
